async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){t.style.display="block",t.innerText="Security error."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count");e.innerText="Loading...";const t=`https://api.counterapi.dev/v1/josemanuel31675-cv/visits/badge.svg?t=${Date.now()}`;e.innerHTML=`<div style="padding:20px"><img src="${t}" alt="Visits Count" style="transform:scale(2);margin-bottom:20px"><p style="font-size:.9rem;color:#666;margin-top:15px">Badge updated in real-time.</p><a href="https://api.counterapi.dev/v1/josemanuel31675-cv/visits" target="_blank" style="font-size:.8rem;color:var(--primary);text-decoration:underline">View Raw JSON Data</a></div>`;try{const t=encodeURIComponent("https://api.counterapi.dev/v1/josemanuel31675-cv/visits"),n=await fetch(`https://corsproxy.io/?${t}`);if(n.ok){const t=await n.json();t&&t.count!==undefined&&(e.innerHTML=`<div class="stat-number">${t.count}</div>`)}}catch(n){console.warn("Proxy read failed, showing badge as fallback.")}}
